185	void vpr_init(const int argc, const char** argv, t_options* options, t_vpr_setup* vpr_setup, t_arch* arch) {
186	    vpr_initialize_logging();
187	
188	    /* Print title message */
189	    vpr_print_title();
190	
191	    /* Read in user options */
192	    *options = read_options(argc, argv);
193	
194	    //Print out the arguments passed to VPR.
195	    //This provides a reference in the log file to exactly
196	    //how VPR was run, aiding in re-producibility
197	    vpr_print_args(argc, argv);
198	
199	    vpr_init_with_options(options, vpr_setup, arch);
200	}
201	
202	/**
203	 * @brief  Initialize VPR with options
204	 *
205	 * 1. Read Arch
206	 * 2. Read Circuit
207	 * 3. Sanity check all three
208	 */
209	void vpr_init_with_options(const t_options* options, t_vpr_setup* vpr_setup, t_arch* arch) {
210	    //Set the number of parallel workers
211	    // We determine the number of workers in the following order:
212	    //  1. An explicitly specified command-line argument
213	    //  2. An environment variable
214	    //  3. The default value
215	    size_t num_workers;
216	    if (options->num_workers.provenance() == argparse::Provenance::SPECIFIED) {
217	        //Explicit command-line
218	        num_workers = options->num_workers.value();
219	    } else {
220	        const char* env_value = std::getenv("VPR_NUM_WORKERS");
221	        if (env_value != nullptr) {
222	            //VPR specific environment variable
223	            num_workers = vtr::atou(env_value);
224	        } else {
225	            //Command-line default value
226	            VTR_ASSERT(options->num_workers.provenance() == argparse::Provenance::DEFAULT);
227	            num_workers = options->num_workers.value();
228	        }
229	    }
230	
231	#ifdef VPR_USE_TBB
232	    //Using Thread Building Blocks
233	    if (num_workers == 0) {
234	        //Use default concurrency (i.e. maximum concurrency)
235	        num_workers = tbb::this_task_arena::max_concurrency();
236	    }
237	
238	    VTR_LOG("Using up to %zu parallel worker(s)\n", num_workers);
239	#else
240	    //No parallel execution support
241	    if (num_workers != 1) {
242	        VTR_LOG_WARN("VPR was compiled without parallel execution support, ignoring the specified number of workers (%zu)",
