380	/** Port equivalence does not make sense during flat routing.
381	 * Remove port equivalence from all ports in the architecture */
382	static void unset_port_equivalences(DeviceContext& device_ctx) {
383	    for (auto& physical_type : device_ctx.physical_tile_types) {
384	        for (auto& sub_tile : physical_type.sub_tiles) {
385	            for (auto& port : sub_tile.ports) {
386	                port.equivalent = PortEquivalence::NONE;
387	            }
388	        }
389	    }
390	    for (auto& logical_type : device_ctx.logical_block_types) {
391	        if (!logical_type.pb_type)
392	            continue;
393	        for (int i = 0; i < logical_type.pb_type->num_ports; i++) {
394	            logical_type.pb_type->ports[i].equivalent = PortEquivalence::NONE;
395	        }
396	    }
397	}
